/**
 * js/data-connectors/bridge-market-summary.js
 * Bridge Data Output — Colorado regional market summary connector.
 *
 * Loads the cached file data/market/bridge_co_market_summary.json, which is
 * generated by a GitHub Actions workflow that pulls from the Bridge public API.
 * Provides regional land-cost and market-velocity context for LIHTC feasibility
 * and housing-needs analysis.
 *
 * The cache file is regenerated by the zillow-data-sync workflow.  If the file
 * is absent, a warning is logged and all methods return null / empty results
 * gracefully — callers should check isAvailable() before consuming data.
 *
 * Usage:
 *   BridgeMarketSummary.load().then(function () {
 *     var ctx = BridgeMarketSummary.getLandCostContext(39.74, -104.99);
 *     // ctx.tier → "high"
 *     // ctx.note → "High land costs — typically >$150K/parcel. ..."
 *   });
 *
 * Public API (window.BridgeMarketSummary):
 *   load()                          → Promise<object|null>
 *   isAvailable()                   → boolean
 *   getSummary()                    → object|null
 *   getStatewide()                  → object|null
 *   getRegions()                    → object[]   (sorted by name)
 *   getRuralRegions()               → object[]
 *   getRegionNearPoint(lat, lon)    → object|null
 *   getLandCostContext(lat, lon)    → { tier, medianLandValue, regionName, isRural, note }
 *   getMarketVelocity(lat, lon)     → { transactionCount, priceTrendPct, label }
 */
(function () {
  'use strict';

  /* ── Constants ────────────────────────────────────────────────────── */

  var DATA_PATH = 'data/market/bridge_co_market_summary.json';

  /**
   * Approximate geographic centroids for each region key.
   * Used by getRegionNearPoint() to match a lat/lon to the closest region.
   * Format: [latitude, longitude]
   */
  var REGION_CENTROIDS = {
    front_range_north:          [40.58, -105.08],
    denver_metro:               [39.74, -104.99],
    front_range_south:          [38.83, -104.82],
    pueblo_south_central:       [38.26, -104.61],
    western_slope:              [39.06, -108.55],
    southwest:                  [37.27, -107.88],
    northwest:                  [40.52, -107.55],
    san_luis_valley:            [37.47, -105.87],
    eastern_plains_north:       [40.62, -103.21],
    eastern_plains_central:     [39.26, -103.69],
    eastern_plains_south:       [38.09, -102.62],
    mountain:                   [39.61, -106.09],
    boulder:                    [40.01, -105.27]
  };

  /* ── Module state ─────────────────────────────────────────────────── */

  /** @type {object|null} Full parsed JSON from the cache file. */
  var _summary = null;

  /** @type {boolean} True once the file has been fetched successfully. */
  var _available = false;

  /** @type {Promise|null} Reused promise so load() is idempotent. */
  var _loadPromise = null;

  /* ── Geo helpers ──────────────────────────────────────────────────── */

  /**
   * Convert degrees to radians.
   * @param {number} d
   * @returns {number}
   */
  function _toRad(d) { return d * Math.PI / 180; }

  /**
   * Haversine great-circle distance in miles between two lat/lon pairs.
   * @param {number} lat1
   * @param {number} lon1
   * @param {number} lat2
   * @param {number} lon2
   * @returns {number}
   */
  function _haversine(lat1, lon1, lat2, lon2) {
    var R  = 3958.8;
    var dL = _toRad(lat2 - lat1);
    var dO = _toRad(lon2 - lon1);
    var a  = Math.sin(dL / 2) * Math.sin(dL / 2) +
             Math.cos(_toRad(lat1)) * Math.cos(_toRad(lat2)) *
             Math.sin(dO / 2) * Math.sin(dO / 2);
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  }

  /* ── Data loading ─────────────────────────────────────────────────── */

  /**
   * Fetch the cached market summary JSON.
   * Uses DataService.getJSON when available, otherwise falls back to fetch().
   * Safe to call multiple times — returns the same promise on repeat calls.
   *
   * @returns {Promise<object|null>} Resolves with the parsed summary or null.
   */
  function load() {
    if (_loadPromise) { return _loadPromise; }

    var fetchPromise;

    if (window.DataService &&
        typeof window.DataService.getJSON === 'function' &&
        typeof window.DataService.baseData === 'function') {
      fetchPromise = window.DataService.getJSON(
        window.DataService.baseData('market/bridge_co_market_summary.json')
      );
    } else {
      var doFetch = (typeof window.fetchWithTimeout === 'function')
        ? function () { return window.fetchWithTimeout(DATA_PATH); }
        : function () { return fetch(DATA_PATH); };
      fetchPromise = doFetch().then(function (r) {
        if (!r.ok) { throw new Error('HTTP ' + r.status); }
        return r.json();
      });
    }

    _loadPromise = fetchPromise
      .then(function (data) {
        _summary   = data || null;
        _available = !!_summary;
        return _summary;
      })
      ['catch'](function (err) {
        console.warn('[BridgeMarketSummary] Cache file not found — run the ' +
                     'zillow-data-sync workflow to generate it.');
        window.dataFetchErrors = window.dataFetchErrors || [];
        window.dataFetchErrors.push({
          source: 'BridgeMarketSummary', url: DATA_PATH,
          error: (err && err.message) || String(err), ts: new Date().toISOString()
        });
        _summary   = null;
        _available = false;
        return null;
      });

    return _loadPromise;
  }

  /* ── Public accessors ─────────────────────────────────────────────── */

  /**
   * Returns true if the cache file has been fetched and parsed successfully.
   * @returns {boolean}
   */
  function isAvailable() {
    return _available;
  }

  /**
   * Returns the full parsed JSON object, or null if not yet loaded.
   * @returns {object|null}
   */
  function getSummary() {
    return _summary;
  }

  /**
   * Returns the statewide stats object, or null if not loaded.
   * @returns {object|null}
   */
  function getStatewide() {
    return (_summary && _summary.statewide) ? _summary.statewide : null;
  }

  /**
   * Returns an array of all region objects, sorted ascending by name.
   * Each object is the raw region record from the cache, augmented with
   * a `key` property set to its key in the regions map.
   *
   * @returns {object[]}
   */
  function getRegions() {
    if (!_summary || !_summary.regions) { return []; }

    var regions = _summary.regions;
    var arr = [];
    var keys = Object.keys(regions);
    for (var i = 0; i < keys.length; i++) {
      var k = keys[i];
      var r = regions[k];
      if (r) {
        arr.push(_withKey(r, k));
      }
    }

    arr.sort(function (a, b) {
      var nameA = (a.name || '').toLowerCase();
      var nameB = (b.name || '').toLowerCase();
      if (nameA < nameB) { return -1; }
      if (nameA > nameB) { return  1; }
      return 0;
    });

    return arr;
  }

  /**
   * Returns only regions where is_rural === true, sorted by name.
   * @returns {object[]}
   */
  function getRuralRegions() {
    return getRegions().filter(function (r) { return r.is_rural === true; });
  }

  /**
   * Finds the region whose centroid is closest to the given lat/lon.
   * Returns the matching region data object (with `key` property), or null.
   *
   * @param {number} lat
   * @param {number} lon
   * @returns {object|null}
   */
  function getRegionNearPoint(lat, lon) {
    if (!_summary || !_summary.regions) { return null; }

    var bestKey  = null;
    var bestDist = Infinity;

    var centroidKeys = Object.keys(REGION_CENTROIDS);
    for (var i = 0; i < centroidKeys.length; i++) {
      var k   = centroidKeys[i];
      var c   = REGION_CENTROIDS[k];
      var d   = _haversine(lat, lon, c[0], c[1]);
      if (d < bestDist) {
        bestDist = d;
        bestKey  = k;
      }
    }

    if (!bestKey) { return null; }

    var regionData = _summary.regions[bestKey];
    return regionData ? _withKey(regionData, bestKey) : null;
  }

  /* ── Contextual helpers ───────────────────────────────────────────── */

  /**
   * Returns land-cost context for the region nearest to the given lat/lon.
   *
   * @param {number} lat
   * @param {number} lon
   * @returns {{ tier: string, medianLandValue: number|null, regionName: string|null,
   *             isRural: boolean, note: string }}
   */
  function getLandCostContext(lat, lon) {
    var region = getRegionNearPoint(lat, lon);

    var tier            = (region && region.land_cost_tier) || 'unknown';
    var medianLandValue = (region && region.median_land_value != null)
      ? region.median_land_value
      : null;
    var regionName      = (region && region.name) || null;
    var isRural         = !!(region && region.is_rural);

    var noteMap = {
      low:      'Low land costs — typically <$50K/parcel. Strong affordability for LIHTC development.',
      moderate: 'Moderate land costs — typically $50K\u2013$150K/parcel. Standard LIHTC feasibility.',
      high:     'High land costs — typically >$150K/parcel. May require basis boost or gap financing.',
      unknown:  'Land cost data pending Bridge API sync.'
    };

    var note = noteMap[tier] || noteMap.unknown;

    return {
      tier:            tier,
      medianLandValue: medianLandValue,
      regionName:      regionName,
      isRural:         isRural,
      note:            note
    };
  }

  /**
   * Returns market-velocity metrics for the region nearest to the given lat/lon.
   * Label is "active" (>= 50 transactions), "moderate" (>= 20), or "quiet" (< 20).
   *
   * @param {number} lat
   * @param {number} lon
   * @returns {{ transactionCount: number|null, priceTrendPct: number|null,
   *             label: string }}
   */
  function getMarketVelocity(lat, lon) {
    var region = getRegionNearPoint(lat, lon);

    var transactionCount = (region && region.transaction_count_12mo != null)
      ? region.transaction_count_12mo
      : null;
    var priceTrendPct = (region && region.price_trend_pct != null)
      ? region.price_trend_pct
      : null;

    var label;
    if (transactionCount === null) {
      label = 'unknown';
    } else if (transactionCount >= 50) {
      label = 'active';
    } else if (transactionCount >= 20) {
      label = 'moderate';
    } else {
      label = 'quiet';
    }

    return {
      transactionCount: transactionCount,
      priceTrendPct:    priceTrendPct,
      label:            label
    };
  }

  /* ── Private utilities ────────────────────────────────────────────── */

  /**
   * Returns a shallow copy of the region object with a `key` property added.
   * Avoids mutating the original cached object.
   *
   * @param {object} regionObj
   * @param {string} key
   * @returns {object}
   */
  function _withKey(regionObj, key) {
    var copy = {};
    var props = Object.keys(regionObj);
    for (var i = 0; i < props.length; i++) {
      copy[props[i]] = regionObj[props[i]];
    }
    copy.key = key;
    return copy;
  }

  /* ── Auto-load on DOMContentLoaded ───────────────────────────────── */

  if (typeof document !== 'undefined') {
    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', function () { load(); });
    } else {
      load();
    }
  }

  /* ── Expose ───────────────────────────────────────────────────────── */
  window.BridgeMarketSummary = {
    load:               load,
    isAvailable:        isAvailable,
    getSummary:         getSummary,
    getStatewide:       getStatewide,
    getRegions:         getRegions,
    getRuralRegions:    getRuralRegions,
    getRegionNearPoint: getRegionNearPoint,
    getLandCostContext: getLandCostContext,
    getMarketVelocity:  getMarketVelocity
  };

}());
